<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:InitiatingHeapOccupancyPercent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=45</span></span>
